bool MCustomer::validateJsonForCreation(const Json::Value &pJson, std::string &err)
{
    if(pJson.isMember("id"))
    {
        if(!validJsonOfField(0, "id", pJson["id"], err, true))
            return false;
    }
    if(pJson.isMember("biodata_id"))
    {
        if(!validJsonOfField(1, "biodata_id", pJson["biodata_id"], err, true))
            return false;
    }
    if(pJson.isMember("dob"))
    {
        if(!validJsonOfField(2, "dob", pJson["dob"], err, true))
            return false;
    }
    if(pJson.isMember("gender"))
    {
        if(!validJsonOfField(3, "gender", pJson["gender"], err, true))
            return false;
    }
    if(pJson.isMember("blood_group_id"))
    {
        if(!validJsonOfField(4, "blood_group_id", pJson["blood_group_id"], err, true))
            return false;
    }
    if(pJson.isMember("rhesus_type"))
    {
        if(!validJsonOfField(5, "rhesus_type", pJson["rhesus_type"], err, true))
            return false;
    }
    if(pJson.isMember("height"))
    {
        if(!validJsonOfField(6, "height", pJson["height"], err, true))
            return false;
    }
    if(pJson.isMember("weight"))
    {
        if(!validJsonOfField(7, "weight", pJson["weight"], err, true))
            return false;
    }
    if(pJson.isMember("created_by"))
    {
        if(!validJsonOfField(8, "created_by", pJson["created_by"], err, true))
            return false;
    }
    else
    {
        err="The created_by column cannot be null";
        return false;
    }
    if(pJson.isMember("created_on"))
    {
        if(!validJsonOfField(9, "created_on", pJson["created_on"], err, true))
            return false;
    }
    else
    {
        err="The created_on column cannot be null";
        return false;
    }
    if(pJson.isMember("modified_by"))
    {
        if(!validJsonOfField(10, "modified_by", pJson["modified_by"], err, true))
            return false;
    }
    if(pJson.isMember("modified_on"))
    {
        if(!validJsonOfField(11, "modified_on", pJson["modified_on"], err, true))
            return false;
    }
    if(pJson.isMember("deleted_by"))
    {
        if(!validJsonOfField(12, "deleted_by", pJson["deleted_by"], err, true))
            return false;
    }
    if(pJson.isMember("deleted_on"))
    {
        if(!validJsonOfField(13, "deleted_on", pJson["deleted_on"], err, true))
            return false;
    }
    if(pJson.isMember("is_delete"))
    {
        if(!validJsonOfField(14, "is_delete", pJson["is_delete"], err, true))
            return false;
    }
    return true;
}
